328→            }
329→            // (
330→              if name == "keys/id_github.age" then
331→                {
332→                  # Deploy GitHub SSH key to ~/.ssh/ with correct permissions
333→                  path = "/home/${username}/.ssh/id_ed25519_github";
334→                  mode = "0600";
335→                }
336→              else
337→                { }
338→            )
339→          ) (import ./secrets.nix);
