343→            $DRY_RUN_CMD mkdir -p $VERBOSE_ARG ${config.home.homeDirectory}/.ssh
344→            $DRY_RUN_CMD chmod $VERBOSE_ARG 700 ${config.home.homeDirectory}/.ssh
345→          '';
346→
347→          # Ensure agenix config directory exists
348→          home.activation.ensureAgenixDirectory = config.lib.dag.entryBefore [ "writeBoundary" ] ''
349→            $DRY_RUN_CMD mkdir -p $VERBOSE_ARG ${config.home.homeDirectory}/.config/agenix
350→            $DRY_RUN_CMD chmod $VERBOSE_ARG 700 ${config.home.homeDirectory}/.config/agenix
351→          '';
352→
353→          # Manually deploy agenix secrets during activation
354→          # This ensures secrets are deployed even if the agenix activation hook doesn't run properly
355→          home.activation.deployAgenixSecrets = config.lib.dag.entryAfter [ "writeBoundary" ] ''
356→            # Decrypt and deploy GitHub SSH key if it doesn't exist
357→            if [[ ! -f "${config.home.homeDirectory}/.ssh/id_ed25519_github" ]]; then
358→              echo "Deploying GitHub SSH key from agenix..."
359→              SECRET_FILE="${builtins.toString ../galactica/keys/id_ed25519.age}"
360→              if [[ -f "$SECRET_FILE" ]]; then
361→                $DRY_RUN_CMD ${pkgs.rage}/bin/rage -d -i ${config.home.homeDirectory}/.ssh/id_ed25519 "$SECRET_FILE" -o ${config.home.homeDirectory}/.ssh/id_ed25519_github
362→                $DRY_RUN_CMD chmod $VERBOSE_ARG 0600 ${config.home.homeDirectory}/.ssh/id_ed25519_github
363→                echo "✅ GitHub SSH key deployed successfully"
364→              else
365→                echo "⚠️  Warning: Secret file not found at $SECRET_FILE"
366→              fi
367→            fi
368→          '';
369→
370→          # Import GPG key from agenix (all systems with dotfiles)
371→          # Fails silently if SSH key isn't authorized to decrypt
372→          home.activation.importGpgKey = config.lib.dag.entryAfter [ "linkGeneration" ] ''
373→            $VERBOSE_ECHO "🔑 Starting GPG key import process..."
374→            GPG_SECRET_FILE="${config.home.homeDirectory}/dotfiles/named-hosts/galactica/keys/gpg.age"
375→            GPG_TEMP_FILE="${config.home.homeDirectory}/.config/agenix/gpg.key"
376→
377→            # Create agenix directory if it doesn't exist
378→            mkdir -p "${config.home.homeDirectory}/.config/agenix"
379→
380→            if [[ -f "$GPG_SECRET_FILE" ]]; then
381→              # Check if key is already imported
382→              if ! ${pkgs.gnupg}/bin/gpg --list-secret-keys 2>/dev/null | grep -q "C2E97FCFF482925D"; then
383→                echo "Importing GPG key from agenix..."
384→                # Try to decrypt - will fail silently if SSH key isn't authorized
385→                if ${pkgs.rage}/bin/rage -d -i ${config.home.homeDirectory}/.ssh/id_ed25519 -o "$GPG_TEMP_FILE" "$GPG_SECRET_FILE" 2>/dev/null; then
386→                  ${pkgs.gnupg}/bin/gpg --batch --import "$GPG_TEMP_FILE" 2>/dev/null
387→                  rm -f "$GPG_TEMP_FILE"
388→                  echo "✅ GPG key imported successfully"
389→                fi
390→              else
391→                $VERBOSE_ECHO "ℹ️  GPG key already imported"
392→              fi
393→            fi
394→          '';
395→
396→          # GPG configuration for commit signing
397→          programs.gpg = {
398→            enable = true;
399→            settings = {
400→              default-key = "shunkakinoki@gmail.com";
401→            };
402→          };
403→
404→          # GPG agent configuration
405→          services.gpg-agent = {
406→            enable = true;
407→            enableSshSupport = false;
408→            pinentry.package = pkgs.pinentry-tty;
409→            defaultCacheTtl = 94608000; # 3 years
410→            maxCacheTtl = 94608000; # 3 years
411→          };
412→
413→          # GPG_TTY is set in fish shell init instead of sessionVariables
414→          # because it needs to be evaluated dynamically per shell session
415→          programs.fish.interactiveShellInit = lib.mkAfter ''
416→            set -gx GPG_TTY (tty)
417→          '';
418→        };
419→    }
420→  ]
421→  ++ (if falconDebExists then [ ./falcon.nix ] else [ ]); # CrowdStrike Falcon (only if .deb exists)
422→}
